#include <bits/stdc++.h>
using namespace std;
const int maxn=10;
int n,a[maxn];
string s=" +-";
bool c() {
	int ans=0,t;
	for(int i=1; i<=n; i++) {
		if(a[i]==0) {
			continue;
		}
		t=i;
		for(int j=1+i; j<=n; j++) {
			if(a[j]!=0) {
				break;
			}
			t=t*10+j;
		}
		if(a[i]==1) {
			ans+=t;
		} else {
			ans-=t;
		}
	}
	return ans==0?1:0;
}
void dfs(int pos) {
	if(pos>n) {
		if(c()){
			cout<<1;
			for(int i=2;i<=n;i++){
				cout<<s[a[i]]<<i;
			}
			cout<<"\n";
		}
		return ;
	}
	for(int i=0;i<3;i++){
		a[pos]=i;
		dfs(pos+1);
	}
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	a[1]=1;
	dfs(2);
	return 0;
}
